#!/usr/bin/env python3
"""Validate generated scan reports."""
from pathlib import Path
import json
import sys

root = Path(__file__).resolve().parents[1]

errors = []

# Validate normalized_scan.json
json_path = root / 'reports' / 'normalized_scan.json'
if not json_path.exists():
    errors.append('missing report: reports/normalized_scan.json')
else:
    try:
        data = json.loads(json_path.read_text())
        if 'target' not in data or 'ports' not in data:
            errors.append('reports/normalized_scan.json: missing required fields (target, ports)')
        if not isinstance(data.get('ports'), list):
            errors.append('reports/normalized_scan.json: ports must be a list')
    except json.JSONDecodeError as e:
        errors.append(f'reports/normalized_scan.json: invalid JSON - {e}')

# Validate port_classification.md
md_path = root / 'reports' / 'port_classification.md'
if not md_path.exists():
    errors.append('missing report: reports/port_classification.md')
else:
    content = md_path.read_text()
    if '# Port Classification' not in content:
        errors.append('reports/port_classification.md: missing header')

if errors:
    for error in errors:
        print(error, file=sys.stderr)
    sys.exit(1)
print('OK: All scan reports validated successfully')

